import{_ as e,c as s,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"版本更新: 初始发布和命令修复 | opencode-mystatus","description":"了解 opencode-mystatus v1.0.0 的初始功能，包括多平台额度查询、可视化进度条和多语言支持，以及 v1.0.1 的斜杠命令修复。","frontmatter":{"title":"版本更新: 初始发布和命令修复 | opencode-mystatus","sidebarTitle":"v1.0-v1.0.1","subtitle":"版本更新: 初始发布和命令修复 | opencode-mystatus","description":"了解 opencode-mystatus v1.0.0 的初始功能，包括多平台额度查询、可视化进度条和多语言支持，以及 v1.0.1 的斜杠命令修复。","tags":["版本","更新日志","v1.0.0","v1.0.1"],"order":2},"headers":[],"relativePath":"zh/vbgate/opencode-mystatus/changelog/v100-v101/index.md","filePath":"zh/vbgate/opencode-mystatus/changelog/v100-v101/index.md"}'),n={name:"zh/vbgate/opencode-mystatus/changelog/v100-v101/index.md"};function o(l,a,d,p,h,r){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="v1-0-0-v1-0-1-初始版本发布和斜杠命令修复" tabindex="-1">v1.0.0 - v1.0.1：初始版本发布和斜杠命令修复 <a class="header-anchor" href="#v1-0-0-v1-0-1-初始版本发布和斜杠命令修复" aria-label="Permalink to &quot;v1.0.0 - v1.0.1：初始版本发布和斜杠命令修复&quot;">​</a></h1><h2 id="版本概述" tabindex="-1">版本概述 <a class="header-anchor" href="#版本概述" aria-label="Permalink to &quot;版本概述&quot;">​</a></h2><p><strong>v1.0.0</strong>（2026-01-11）是 opencode-mystatus 的初始版本，带来了多平台额度查询的核心功能。</p><p><strong>v1.0.1</strong>（2026-01-11）立即跟进，修复了斜杠命令支持的关键问题。</p><hr><h2 id="v1-0-1-斜杠命令修复" tabindex="-1">v1.0.1 - 斜杠命令修复 <a class="header-anchor" href="#v1-0-1-斜杠命令修复" aria-label="Permalink to &quot;v1.0.1 - 斜杠命令修复&quot;">​</a></h2><h3 id="修复问题" tabindex="-1">修复问题 <a class="header-anchor" href="#修复问题" aria-label="Permalink to &quot;修复问题&quot;">​</a></h3><p><strong>包含 <code>command/</code> 目录到 npm 包</strong></p><ul><li><strong>问题描述</strong>：v1.0.0 发布后，发现斜杠命令 <code>/mystatus</code> 无法正常工作</li><li><strong>原因分析</strong>：npm 打包时遗漏了 <code>command/</code> 目录，导致 OpenCode 无法识别斜杠命令</li><li><strong>修复方案</strong>：更新 <code>package.json</code> 的 <code>files</code> 字段，确保 <code>command/</code> 目录被包含在发布包中</li><li><strong>影响范围</strong>：仅影响通过 npm 安装的用户，手动安装不受影响</li></ul><h3 id="升级建议" tabindex="-1">升级建议 <a class="header-anchor" href="#升级建议" aria-label="Permalink to &quot;升级建议&quot;">​</a></h3><p>如果你已经安装了 v1.0.0，建议立即升级到 v1.0.1 以获得完整的斜杠命令支持：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 升级到最新版本</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><hr><h2 id="v1-0-0-初始版本发布" tabindex="-1">v1.0.0 - 初始版本发布 <a class="header-anchor" href="#v1-0-0-初始版本发布" aria-label="Permalink to &quot;v1.0.0 - 初始版本发布&quot;">​</a></h2><h3 id="新增功能" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><p><strong>1. 多平台额度查询</strong></p><p>支持一键查询以下平台的额度使用情况：</p><table tabindex="0"><thead><tr><th>平台</th><th>支持的订阅类型</th><th>额度类型</th></tr></thead><tbody><tr><td>OpenAI</td><td>Plus/Team/Pro</td><td>3 小时限额、24 小时限额</td></tr><tr><td>智谱 AI</td><td>Coding Plan</td><td>5 小时 Token 限额、MCP 月度配额</td></tr><tr><td>Google Cloud</td><td>Antigravity</td><td>G3 Pro、G3 Image、G3 Flash、Claude</td></tr></tbody></table><p><strong>2. 可视化进度条</strong></p><p>直观展示额度使用情况：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OpenAI (user@example.com)</span></span>
<span class="line"><span>━━━━━━━━━━━━━━━━━━━━ 75%</span></span>
<span class="line"><span>已用 750 / 1000 次请求</span></span></code></pre></div><p><strong>3. 多语言支持</strong></p><ul><li>中文（简体）</li><li>英文</li></ul><p>语言自动检测，无需手动切换。</p><p><strong>4. API Key 安全脱敏</strong></p><p>所有敏感信息（API Key、OAuth Token）自动脱敏显示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>智谱 AI (zhipuai-coding-plan)</span></span>
<span class="line"><span>API Key: sk-a1b2****xyz</span></span></code></pre></div><hr><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><h3 id="斜杠命令-推荐" tabindex="-1">斜杠命令（推荐） <a class="header-anchor" href="#斜杠命令-推荐" aria-label="Permalink to &quot;斜杠命令（推荐）&quot;">​</a></h3><p>在 OpenCode 中输入：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><h3 id="自然语言" tabindex="-1">自然语言 <a class="header-anchor" href="#自然语言" aria-label="Permalink to &quot;自然语言&quot;">​</a></h3><p>你也可以用自然语言询问：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查看我的所有 AI 平台额度</span></span></code></pre></div><hr><h2 id="升级指南" tabindex="-1">升级指南 <a class="header-anchor" href="#升级指南" aria-label="Permalink to &quot;升级指南&quot;">​</a></h2><h3 id="从-v1-0-0-升级到-v1-0-1" tabindex="-1">从 v1.0.0 升级到 v1.0.1 <a class="header-anchor" href="#从-v1-0-0-升级到-v1-0-1" aria-label="Permalink to &quot;从 v1.0.0 升级到 v1.0.1&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><p>升级后，重启 OpenCode 即可使用斜杠命令 <code>/mystatus</code>。</p><h3 id="首次安装" tabindex="-1">首次安装 <a class="header-anchor" href="#首次安装" aria-label="Permalink to &quot;首次安装&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><p>安装完成后，在 OpenCode 中输入 <code>/mystatus</code> 即可查询所有平台的额度。</p><hr><h2 id="已知限制" tabindex="-1">已知限制 <a class="header-anchor" href="#已知限制" aria-label="Permalink to &quot;已知限制&quot;">​</a></h2><ul><li>v1.0.0 不支持 GitHub Copilot（v1.2.0 新增）</li><li>v1.0.0 不支持 Z.ai（v1.1.0 新增）</li></ul><p>如需使用这些功能，请升级到最新版本。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>查看 <a href="./../v120-v124/">v1.2.0 - v1.2.4 更新日志</a> 了解 GitHub Copilot 支持等新功能。</p>`,50)])])}const g=e(n,[["render",o]]);export{u as __pageData,g as default};
